@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <!-- Stats Bar -->
    <div class="stats-bar d-flex gap-3 mb-3 p-2 bg-light rounded">
        <span><strong>Total:</strong> @_allTasks.Count</span>
        <span><strong>To Do:</strong> @GetColumnTasks("To Do").Count</span>
        <span><strong>In Progress:</strong> @GetColumnTasks("In Progress").Count</span>
        <span><strong>Done:</strong> @GetColumnTasks("Done").Count</span>
        <span class="text-danger"><strong>Overdue:</strong> @_allTasks.Count(t => t.DueDate < DateTime.Today)</span>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="_searchText" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="d-flex gap-3">
        @foreach (var column in _columns)
        {
            var tasks = GetFilteredColumnTasks(column);
            var colIndex = Array.IndexOf(_columns, column);

            <div class="kanban-column flex-fill border rounded p-2" style="min-width: 250px;">
                <h4>@column <span class="badge bg-secondary">@tasks.Count</span></h4>

                @foreach (var task in tasks)
                {
                    <div class="card mb-2">
                        <div class="card-body p-2">
                            <h6 class="card-title">@task.Title</h6>
                            <p class="card-text mb-1"><small>@task.Assignee</small></p>
                            <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                            <span class="ms-2"><small>@task.DueDate.ToString("MMM dd")</small></span>
                            <div class="mt-2">
                                @if (colIndex > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary me-1"
                                            @onclick="() => MoveTask(task, _columns[colIndex - 1])">
                                        Move Left
                                    </button>
                                }
                                @if (colIndex < _columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTask(task, _columns[colIndex + 1])">
                                        Move Right
                                    </button>
                                }
                            </div>
                        </div>
                    </div>
                }

                @if (_addingToColumn == column)
                {
                    <div class="border rounded p-2 mt-2">
                        <input type="text" class="form-control form-control-sm mb-1" placeholder="Title"
                               @bind="_newTitle" />
                        <input type="text" class="form-control form-control-sm mb-1" placeholder="Assignee"
                               @bind="_newAssignee" />
                        <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control form-control-sm mb-1"
                               @bind="_newDueDate" />
                        <div class="d-flex gap-1">
                            <button class="btn btn-sm btn-primary" @onclick="SaveNewTask">Save</button>
                            <button class="btn btn-sm btn-secondary" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary mt-2"
                            @onclick="() => StartAdd(column)">
                        Add Task
                    </button>
                }
            </div>
        }
    </div>
}

@code {
    private readonly string[] _columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    // Add task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status) =>
        _allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrEmpty(_searchText)
                || t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase))
            .ToList();

    private string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = _allTasks.IndexOf(task);
            if (index >= 0)
            {
                _allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd()
    {
        _addingToColumn = null;
    }

    private async Task SaveNewTask()
    {
        if (string.IsNullOrWhiteSpace(_newTitle) || _addingToColumn is null)
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // CreateTaskAsync creates with default status; update if not "To Do"
            if (_addingToColumn != "To Do")
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, _addingToColumn);
                created = created with { Status = _addingToColumn };
            }
            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

