    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = _allTasks.IndexOf(task);
            if (index >= 0)
            {
                _allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

